1	/**
2	 * The Cartograph — vision/charge/piece decomposition-ladder apparatus.
3	 *
4	 * Stands up the data-and-typed-API substrate for the four-level
5	 * decomposition ladder:
6	 *
7	 *   vision (top, patron-owned, long-lived)
8	 *     → charge (first decomposition, the unit of patron walkthrough)
9	 *       → piece (recursive, internal organization, self-nesting)
10	 *         → mandate (existing leaf where rigs attach)
11	 *
12	 * Three writ types (`vision`, `charge`, `piece`) are contributed to the
13	 * Clerk via `clerk.registerWritType` from `start()`. Each type uses a
14	 * six-state mandate-clone lifecycle without `childrenBehavior` cascade —
15	 * patron-walkthrough semantics are coordinated by the typed API and
16	 * downstream consumers, not by registry-side cascade rules.
17	 *
18	 * Three companion books (`visions`, `charges`, `pieces`) under owner id
19	 * `cartograph` shadow each writ with a typed companion document. The
20	 * doc's primary key is the writ id one-for-one. Vision text lives on
21	 * `writ.body`; the companion docs carry typed metadata only.
22	 *
23	 * The typed API is the **only** layer that enforces the ladder's parent
24	 * invariants — vision has no parent, `charge.parentId` must be a vision,
25	 * `piece.parentId` must be a charge or piece. Raw `clerk.post({ type:
26	 * 'vision' })` continues to succeed without parent-type checks.
27	 *
28	 * Each `createX` method opens a single `stacks.transaction(...)` and
29	 * writes the writ row and the companion doc inside one boundary. Parent
30	 * existence, parent-not-terminal, codex inheritance, and id generation
31	 * mirror Clerk's `post()` validation byte-for-byte. `transitionX`
32	 * methods update both `writ.phase` and the companion doc's `stage`
33	 * field atomically inside one transaction.
34	 */
35	
36	import type { Plugin, StartupContext } from '@shardworks/nexus-core';
37	import { guild, generateId } from '@shardworks/nexus-core';
38	import type {
39	  Book,
40	  BookQuery,
41	  StacksApi,
42	  WhereClause,
43	} from '@shardworks/stacks-apparatus';
44	import type {
45	  ClerkApi,
46	  WritDoc,
47	  WritPhase,
48	  WritTypeConfig,
49	} from '@shardworks/clerk-apparatus';
50	
51	import type {
52	  CartographApi,
53	  ChargeDoc,
54	  ChargeFilters,
55	  ChargeStage,
56	  CreateChargeRequest,
57	  CreatePieceRequest,
58	  CreateVisionRequest,
59	  PieceDoc,
60	  PieceFilters,
61	  PieceStage,
62	  TransitionChargeRequest,
63	  TransitionPieceRequest,
64	  TransitionVisionRequest,
65	  VisionDoc,
66	  VisionFilters,
67	  VisionStage,
68	} from './types.ts';
69	
70	import {
71	  visionCreate,
72	  visionShow,
73	  visionList,
74	  visionPatch,
75	  visionTransition,
76	  visionApply,
77	  chargeCreate,
78	  chargeShow,
79	  chargeList,
80	  chargePatch,
81	  chargeTransition,
82	  pieceCreate,
83	  pieceShow,
84	  pieceList,
85	  piecePatch,
86	  pieceTransition,
87	} from './tools/index.ts';
88	
89	// ── Writ-type configs ────────────────────────────────────────────────
90	//
91	// Six-state mandate-clone byte-shape, identical to astrolabe's
92	// `STEP_CONFIG` / `OBSERVATION_SET_CONFIG`. NO `childrenBehavior`
93	// cascade — the typed API and downstream consumers coordinate
94	// patron-walkthrough semantics; the registry stays generic.
95	
96	const VISION_CONFIG: WritTypeConfig = {
97	  name: 'vision',
98	  states: [
99	    { name: 'new', classification: 'initial', allowedTransitions: ['open', 'cancelled'] },
100	    { name: 'open', classification: 'active', allowedTransitions: ['stuck', 'completed', 'failed', 'cancelled'] },
101	    { name: 'stuck', classification: 'active', attrs: ['stuck'], allowedTransitions: ['open', 'failed', 'cancelled'] },
102	    { name: 'completed', classification: 'terminal', attrs: ['success'], allowedTransitions: [] },
103	    { name: 'failed', classification: 'terminal', attrs: ['failure'], allowedTransitions: [] },
104	    { name: 'cancelled', classification: 'terminal', attrs: ['cancelled'], allowedTransitions: [] },
105	  ],
106	};
107	
108	const CHARGE_CONFIG: WritTypeConfig = {
109	  name: 'charge',
110	  states: [
111	    { name: 'new', classification: 'initial', allowedTransitions: ['open', 'cancelled'] },
112	    { name: 'open', classification: 'active', allowedTransitions: ['stuck', 'completed', 'failed', 'cancelled'] },
113	    { name: 'stuck', classification: 'active', attrs: ['stuck'], allowedTransitions: ['open', 'failed', 'cancelled'] },
114	    { name: 'completed', classification: 'terminal', attrs: ['success'], allowedTransitions: [] },
115	    { name: 'failed', classification: 'terminal', attrs: ['failure'], allowedTransitions: [] },
116	    { name: 'cancelled', classification: 'terminal', attrs: ['cancelled'], allowedTransitions: [] },
117	  ],
118	};
119	
120	const PIECE_CONFIG: WritTypeConfig = {
121	  name: 'piece',
122	  states: [
123	    { name: 'new', classification: 'initial', allowedTransitions: ['open', 'cancelled'] },
124	    { name: 'open', classification: 'active', allowedTransitions: ['stuck', 'completed', 'failed', 'cancelled'] },
125	    { name: 'stuck', classification: 'active', attrs: ['stuck'], allowedTransitions: ['open', 'failed', 'cancelled'] },
126	    { name: 'completed', classification: 'terminal', attrs: ['success'], allowedTransitions: [] },
127	    { name: 'failed', classification: 'terminal', attrs: ['failure'], allowedTransitions: [] },
128	    { name: 'cancelled', classification: 'terminal', attrs: ['cancelled'], allowedTransitions: [] },
129	  ],
130	};
131	
132	/**
133	 * Initial stage that pairs with a writ's `new` initial phase. The
134	 * typed-API `createX` methods set this on the companion doc at creation
135	 * time so the doc's stage starts in lockstep with the writ's phase.
136	 */
137	const INITIAL_STAGE = 'draft' as const;
138	
139	/**
140	 * Allowed initial (phase, stage) pairs for `createVision`. A vision
141	 * cannot be born retired, so terminal stages (`sunset`, `cancelled`)
142	 * are deliberately absent — to drive a vision to a terminal state,
143	 * create it then call `transitionVision`.
144	 *
145	 * The mapping mirrors the call-site logic the on-disk vision-apply tool
146	 * uses when deriving the writ phase from the patron's sidecar `stage`.
147	 */
148	const VISION_INITIAL_STAGE_TO_PHASE: Record<string, WritPhase> = {
149	  draft: 'new',
150	  active: 'open',
151	};
152	
153	/**
154	 * Return true when the given writ is in a terminal state per its
155	 * registered type config. Replicates `clerk.isTerminal()` against the
156	 * locally-resolved config so the call site doesn't need to round-trip
157	 * through the Clerk API mid-transaction.
158	 */
159	function isTerminalPhase(
160	  writ: WritDoc,
161	  getConfig: (name: string) => WritTypeConfig | undefined,
162	): boolean {
163	  const config = getConfig(writ.type);
164	  if (!config) {
165	    throw new Error(
166	      `[cartograph] writ "${writ.id}" carries unregistered type "${writ.type}".`,
167	    );
168	  }
169	  const state = config.states.find((s) => s.name === writ.phase);
170	  if (!state) {
171	    throw new Error(
172	      `[cartograph] writ "${writ.id}" carries phase "${writ.phase}" not declared in type "${writ.type}".`,
173	    );
174	  }
175	  return state.classification === 'terminal';
176	}
177	
178	// ── Factory ──────────────────────────────────────────────────────────
179	
180	export function createCartograph(): Plugin {
181	  let stacks: StacksApi;
182	  let clerk: ClerkApi;
183	  let visionsBook: Book<VisionDoc>;
184	  let chargesBook: Book<ChargeDoc>;
185	  let piecesBook: Book<PieceDoc>;
186	
187	  // ── Generic helpers ────────────────────────────────────────────────
188	
189	  /**
190	   * Build a list-style query for one of the three companion books.
191	   * Mirrors astrolabe's `list` body; only the field name differs (`stage`
192	   * vs `status`).
193	   */
194	  function buildListQuery(filters?: {
195	    stage?: string;
196	    codex?: string;
197	    limit?: number;
198	    offset?: number;
199	  }): BookQuery {
200	    const conditions: WhereClause = [];
201	    if (filters?.stage !== undefined) conditions.push(['stage', '=', filters.stage]);
202	    if (filters?.codex !== undefined) conditions.push(['codex', '=', filters.codex]);
203	    const limit = filters?.limit ?? 20;
204	    const offset = filters?.offset;
205	    return {
206	      ...(conditions.length > 0 ? { where: conditions } : {}),
207	      orderBy: ['createdAt', 'desc'],
208	      limit,
209	      ...(offset !== undefined ? { offset } : {}),
210	    };
211	  }
212	
213	  /**
214	   * Validate parent existence, not-terminal, and (optionally) the parent's
215	   * type. Returns the parent writ doc on success. The transactional
216	   * writs-book handle is passed in by the caller so all reads/writes
217	   * commit under a single boundary.
218	   */
219	  async function validateParent(
220	    txWritsBook: Book<WritDoc>,
221	    parentId: string,
222	    childId: string,
223	    options: { allowedParentTypes?: string[]; childTypeName: string },
224	  ): Promise<WritDoc> {
225	    const parent = await txWritsBook.get(parentId);
226	    if (!parent) {
227	      throw new Error(`Parent writ "${parentId}" not found.`);
228	    }
229	    if (parentId === childId) {
230	      throw new Error(`Cannot create a writ as its own parent.`);
231	    }
232	    if (isTerminalPhase(parent, (name) => clerk.getWritTypeConfig(name))) {
233	      throw new Error(
234	        `Cannot add children to writ "${parentId}": phase is "${parent.phase}" (terminal). Children can only be added to writs in non-terminal states.`,
235	      );
236	    }
237	    if (options.allowedParentTypes !== undefined) {
238	      if (!options.allowedParentTypes.includes(parent.type)) {
239	        const allowed = options.allowedParentTypes.map((t) => `"${t}"`).join(' or ');
240	        throw new Error(
241	          `[cartograph] cannot create ${options.childTypeName} under writ "${parentId}": parent type is "${parent.type}", expected ${allowed}.`,
242	        );
243	      }
244	    }
245	    return parent;
246	  }
247	
248	  // ── API ────────────────────────────────────────────────────────────
249	
250	  const api: CartographApi = {
251	    // ── Vision ────────────────────────────────────────────────────
252	
253	    async createVision(request: CreateVisionRequest): Promise<VisionDoc> {
254	      // Runtime guard for the typed-API parent invariant: a vision has
255	      // no parent. The static `CreateVisionRequest` shape does not
256	      // include `parentId`, but a structurally-typed caller could still
257	      // pass one — reject explicitly so the rule is enforced at the
258	      // boundary.
259	      const maybeParentId = (request as { parentId?: unknown }).parentId;
260	      if (typeof maybeParentId === 'string' && maybeParentId.length > 0) {
261	        throw new Error(
262	          '[cartograph] createVision: a vision is a top-level writ and cannot have a parent — refusing to create a vision with parentId.',
263	        );
264	      }
265	
266	      // Initial-state resolution. Defaults to (phase=new, stage=draft) so
267	      // existing callers are unaffected. A caller may supply either or
268	      // both; whatever they supply must agree with the fixed mapping in
269	      // VISION_INITIAL_STAGE_TO_PHASE. Terminal initial states
270	      // (sunset/cancelled) are rejected — a vision cannot be born retired.
271	      const requestedStage: VisionStage = request.stage ?? INITIAL_STAGE;
272	      const expectedPhase = VISION_INITIAL_STAGE_TO_PHASE[requestedStage];
273	      if (expectedPhase === undefined) {
274	        throw new Error(
275	          `[cartograph] createVision: stage "${requestedStage}" is not a valid initial stage. ` +
276	            `A vision cannot be born retired — allowed initial stages are "draft" and "active". ` +
277	            `To drive a vision to a terminal state, create it then call transitionVision.`,
278	        );
279	      }
280	      const requestedPhase: WritPhase = request.phase ?? expectedPhase;
281	      if (requestedPhase !== expectedPhase) {
282	        throw new Error(
283	          `[cartograph] createVision: phase "${requestedPhase}" does not pair with stage "${requestedStage}". ` +
284	            `Allowed initial pairs are (phase=new, stage=draft) and (phase=open, stage=active).`,
285	        );
286	      }
287	      // Validate phase against the registered VISION_CONFIG, mirroring
288	      // transitionVision's defensive check. Catches an unregistered or
289	      // typo'd phase value before we write the writ row.
290	      const visionConfig = clerk.getWritTypeConfig('vision');
291	      if (!visionConfig) {
292	        throw new Error(
293	          '[cartograph] createVision: writ type "vision" is not registered with the Clerk.',
294	        );
295	      }
296	      const requestedState = visionConfig.states.find((s) => s.name === requestedPhase);
297	      if (!requestedState) {
298	        throw new Error(
299	          `[cartograph] createVision: phase "${requestedPhase}" is not declared in writ type "vision".`,
300	        );
301	      }
302	
303	      // The createX methods cannot delegate to clerk.post because Clerk's
304	      // `post` does not accept an external transaction context, and the
305	      // writ row + companion doc must commit under one boundary.
306	      // Replicating Clerk's validation logic here is the cost of being a
307	      // typed atomic surface.
308	      return stacks.transaction(async (tx) => {
309	        const txWritsBook = tx.book<WritDoc>('clerk', 'writs');
310	        const txVisionsBook = tx.book<VisionDoc>('cartograph', 'visions');
311	
312	        const childId = generateId('w', 6);
313	        const now = new Date().toISOString();
314	
315	        const writ: WritDoc = {
316	          id: childId,
317	          type: 'vision',
318	          phase: requestedPhase,
319	          title: request.title,
320	          body: request.body,
321	          ...(request.codex !== undefined ? { codex: request.codex } : {}),
322	          createdAt: now,
323	          updatedAt: now,
324	        };
325	
326	        await txWritsBook.put(writ);
327	
328	        const doc: VisionDoc = {
329	          id: childId,
330	          stage: requestedStage,
331	          ...(request.codex !== undefined ? { codex: request.codex } : {}),
332	          createdAt: now,
333	          updatedAt: now,
334	        };
335	
336	        await txVisionsBook.put(doc);
337	        return doc;
338	      });
339	    },
340	
341	    async showVision(id: string): Promise<VisionDoc> {
342	      const doc = await visionsBook.get(id);
343	      if (!doc) {
344	        throw new Error(`Vision "${id}" not found.`);
345	      }
346	      return doc;
347	    },
348	
349	    async listVisions(filters?: VisionFilters): Promise<VisionDoc[]> {
350	      return visionsBook.find(buildListQuery(filters));
351	    },
352	
353	    async patchVision(
354	      id: string,
355	      fields: Partial<Omit<VisionDoc, 'id'>>,
356	    ): Promise<VisionDoc> {
357	      return visionsBook.patch(id, fields);
358	    },
359	
360	    async transitionVision(
361	      id: string,
362	      request: TransitionVisionRequest,
363	    ): Promise<VisionDoc> {
364	      // Lifecycle coupling lives on the typed API. The caller specifies
365	      // both target phase and target stage explicitly because a single
366	      // phase may map to multiple stages (e.g. failed → cancelled vs
367	      // failed → sunset).
368	      return stacks.transaction(async (tx) => {
369	        const txWritsBook = tx.book<WritDoc>('clerk', 'writs');
370	        const txVisionsBook = tx.book<VisionDoc>('cartograph', 'visions');
371	
372	        const writ = await txWritsBook.get(id);
373	        if (!writ) {
374	          throw new Error(`Writ "${id}" not found.`);
375	        }
376	
377	        const config = clerk.getWritTypeConfig(writ.type);
378	        if (!config) {
379	          throw new Error(
380	            `[cartograph] writ "${id}" carries unregistered type "${writ.type}".`,
381	          );
382	        }
383	        const currentState = config.states.find((s) => s.name === writ.phase);
384	        if (!currentState) {
385	          throw new Error(
386	            `[cartograph] writ "${id}" carries phase "${writ.phase}" not declared in type "${writ.type}".`,
387	          );
388	        }
389	        if (!currentState.allowedTransitions.includes(request.phase)) {
390	          const legal =
391	            currentState.allowedTransitions.length === 0
392	              ? 'none (terminal state)'
393	              : currentState.allowedTransitions.map((s) => `"${s}"`).join(', ');
394	          throw new Error(
395	            `Cannot transition writ "${id}" from "${writ.phase}" to "${request.phase}": legal transitions from "${writ.phase}" are ${legal}.`,
396	          );
397	        }
398	        const targetState = config.states.find((s) => s.name === request.phase);
399	        if (!targetState) {
400	          throw new Error(
401	            `[cartograph] writ type "${writ.type}" has no state "${request.phase}".`,
402	          );
403	        }
404	        const isTerminal = targetState.classification === 'terminal';
405	
406	        const now = new Date().toISOString();
407	        const writPatch: Partial<Omit<WritDoc, 'id'>> = {
408	          phase: request.phase,
409	          updatedAt: now,
410	          ...(isTerminal ? { resolvedAt: now } : {}),
411	          ...(request.resolution !== undefined ? { resolution: request.resolution } : {}),
412	        };
413	        await txWritsBook.patch(id, writPatch);
414	
415	        return txVisionsBook.patch(id, { stage: request.stage, updatedAt: now });
416	      });
417	    },
418	
419	    // ── Charge ────────────────────────────────────────────────────
420	
421	    async createCharge(request: CreateChargeRequest): Promise<ChargeDoc> {
422	      return stacks.transaction(async (tx) => {
423	        const txWritsBook = tx.book<WritDoc>('clerk', 'writs');
424	        const txChargesBook = tx.book<ChargeDoc>('cartograph', 'charges');
425	
426	        const childId = generateId('w', 6);
427	        const now = new Date().toISOString();
428	        const initialPhase = 'new';
429	
430	        if (!request.parentId) {
431	          throw new Error(
432	            '[cartograph] createCharge requires a parentId — a charge must be created under a vision.',
433	          );
434	        }
435	
436	        const parent = await validateParent(txWritsBook, request.parentId, childId, {
437	          allowedParentTypes: ['vision'],
438	          childTypeName: 'charge',
439	        });
440	
441	        const codex = request.codex ?? parent.codex;
442	
443	        const writ: WritDoc = {
444	          id: childId,
445	          type: 'charge',
446	          phase: initialPhase,
447	          title: request.title,
448	          body: request.body,
449	          ...(codex !== undefined ? { codex } : {}),
450	          parentId: request.parentId,
451	          createdAt: now,
452	          updatedAt: now,
453	        };
454	
455	        await txWritsBook.put(writ);
456	
457	        const doc: ChargeDoc = {
458	          id: childId,
459	          stage: INITIAL_STAGE,
460	          ...(codex !== undefined ? { codex } : {}),
461	          createdAt: now,
462	          updatedAt: now,
463	        };
464	
465	        await txChargesBook.put(doc);
466	        return doc;
467	      });
468	    },
469	
470	    async showCharge(id: string): Promise<ChargeDoc> {
471	      const doc = await chargesBook.get(id);
472	      if (!doc) {
473	        throw new Error(`Charge "${id}" not found.`);
474	      }
475	      return doc;
476	    },
477	
478	    async listCharges(filters?: ChargeFilters): Promise<ChargeDoc[]> {
479	      return chargesBook.find(buildListQuery(filters));
480	    },
481	
482	    async patchCharge(
483	      id: string,
484	      fields: Partial<Omit<ChargeDoc, 'id'>>,
485	    ): Promise<ChargeDoc> {
486	      return chargesBook.patch(id, fields);
487	    },
488	
489	    async transitionCharge(
490	      id: string,
491	      request: TransitionChargeRequest,
492	    ): Promise<ChargeDoc> {
493	      return stacks.transaction(async (tx) => {
494	        const txWritsBook = tx.book<WritDoc>('clerk', 'writs');
495	        const txChargesBook = tx.book<ChargeDoc>('cartograph', 'charges');
496	
497	        const writ = await txWritsBook.get(id);
498	        if (!writ) {
499	          throw new Error(`Writ "${id}" not found.`);
500	        }
501	
502	        const config = clerk.getWritTypeConfig(writ.type);
503	        if (!config) {
504	          throw new Error(
505	            `[cartograph] writ "${id}" carries unregistered type "${writ.type}".`,
506	          );
507	        }
508	        const currentState = config.states.find((s) => s.name === writ.phase);
509	        if (!currentState) {
510	          throw new Error(
511	            `[cartograph] writ "${id}" carries phase "${writ.phase}" not declared in type "${writ.type}".`,
512	          );
513	        }
514	        if (!currentState.allowedTransitions.includes(request.phase)) {
515	          const legal =
516	            currentState.allowedTransitions.length === 0
517	              ? 'none (terminal state)'
518	              : currentState.allowedTransitions.map((s) => `"${s}"`).join(', ');
519	          throw new Error(
520	            `Cannot transition writ "${id}" from "${writ.phase}" to "${request.phase}": legal transitions from "${writ.phase}" are ${legal}.`,
521	          );
522	        }
523	        const targetState = config.states.find((s) => s.name === request.phase);
524	        if (!targetState) {
525	          throw new Error(
526	            `[cartograph] writ type "${writ.type}" has no state "${request.phase}".`,
527	          );
528	        }
529	        const isTerminal = targetState.classification === 'terminal';
530	
531	        const now = new Date().toISOString();
532	        const writPatch: Partial<Omit<WritDoc, 'id'>> = {
533	          phase: request.phase,
534	          updatedAt: now,
535	          ...(isTerminal ? { resolvedAt: now } : {}),
536	          ...(request.resolution !== undefined ? { resolution: request.resolution } : {}),
537	        };
538	        await txWritsBook.patch(id, writPatch);
539	
540	        return txChargesBook.patch(id, { stage: request.stage, updatedAt: now });
541	      });
542	    },
543	
544	    // ── Piece ─────────────────────────────────────────────────────
545	
546	    async createPiece(request: CreatePieceRequest): Promise<PieceDoc> {
547	      return stacks.transaction(async (tx) => {
548	        const txWritsBook = tx.book<WritDoc>('clerk', 'writs');
549	        const txPiecesBook = tx.book<PieceDoc>('cartograph', 'pieces');
550	
551	        const childId = generateId('w', 6);
552	        const now = new Date().toISOString();
553	        const initialPhase = 'new';
554	
555	        if (!request.parentId) {
556	          throw new Error(
557	            '[cartograph] createPiece requires a parentId — a piece must be created under a charge or piece.',
558	          );
559	        }
560	
561	        const parent = await validateParent(txWritsBook, request.parentId, childId, {
562	          allowedParentTypes: ['charge', 'piece'],
563	          childTypeName: 'piece',
564	        });
565	
566	        const codex = request.codex ?? parent.codex;
567	
568	        const writ: WritDoc = {
569	          id: childId,
570	          type: 'piece',
571	          phase: initialPhase,
572	          title: request.title,
573	          body: request.body,
574	          ...(codex !== undefined ? { codex } : {}),
575	          parentId: request.parentId,
576	          createdAt: now,
577	          updatedAt: now,
578	        };
579	
580	        await txWritsBook.put(writ);
581	
582	        const doc: PieceDoc = {
583	          id: childId,
584	          stage: INITIAL_STAGE,
585	          ...(codex !== undefined ? { codex } : {}),
586	          createdAt: now,
587	          updatedAt: now,
588	        };
589	
590	        await txPiecesBook.put(doc);
591	        return doc;
592	      });
593	    },
594	
595	    async showPiece(id: string): Promise<PieceDoc> {
596	      const doc = await piecesBook.get(id);
597	      if (!doc) {
598	        throw new Error(`Piece "${id}" not found.`);
599	      }
600	      return doc;
601	    },
602	
603	    async listPieces(filters?: PieceFilters): Promise<PieceDoc[]> {
604	      return piecesBook.find(buildListQuery(filters));
605	    },
606	
607	    async patchPiece(
608	      id: string,
609	      fields: Partial<Omit<PieceDoc, 'id'>>,
610	    ): Promise<PieceDoc> {
611	      return piecesBook.patch(id, fields);
612	    },
613	
614	    async transitionPiece(
615	      id: string,
616	      request: TransitionPieceRequest,
617	    ): Promise<PieceDoc> {
618	      return stacks.transaction(async (tx) => {
619	        const txWritsBook = tx.book<WritDoc>('clerk', 'writs');
620	        const txPiecesBook = tx.book<PieceDoc>('cartograph', 'pieces');
621	
622	        const writ = await txWritsBook.get(id);
623	        if (!writ) {
624	          throw new Error(`Writ "${id}" not found.`);
625	        }
626	
627	        const config = clerk.getWritTypeConfig(writ.type);
628	        if (!config) {
629	          throw new Error(
630	            `[cartograph] writ "${id}" carries unregistered type "${writ.type}".`,
631	          );
632	        }
633	        const currentState = config.states.find((s) => s.name === writ.phase);
634	        if (!currentState) {
635	          throw new Error(
636	            `[cartograph] writ "${id}" carries phase "${writ.phase}" not declared in type "${writ.type}".`,
637	          );
638	        }
639	        if (!currentState.allowedTransitions.includes(request.phase)) {
640	          const legal =
641	            currentState.allowedTransitions.length === 0
642	              ? 'none (terminal state)'
643	              : currentState.allowedTransitions.map((s) => `"${s}"`).join(', ');
644	          throw new Error(
645	            `Cannot transition writ "${id}" from "${writ.phase}" to "${request.phase}": legal transitions from "${writ.phase}" are ${legal}.`,
646	          );
647	        }
648	        const targetState = config.states.find((s) => s.name === request.phase);
649	        if (!targetState) {
650	          throw new Error(
651	            `[cartograph] writ type "${writ.type}" has no state "${request.phase}".`,
652	          );
653	        }
654	        const isTerminal = targetState.classification === 'terminal';
655	
656	        const now = new Date().toISOString();
657	        const writPatch: Partial<Omit<WritDoc, 'id'>> = {
658	          phase: request.phase,
659	          updatedAt: now,
660	          ...(isTerminal ? { resolvedAt: now } : {}),
661	          ...(request.resolution !== undefined ? { resolution: request.resolution } : {}),
662	        };
663	        await txWritsBook.patch(id, writPatch);
664	
665	        return txPiecesBook.patch(id, { stage: request.stage, updatedAt: now });
666	      });
667	    },
668	  };
669	
670	  // ── Apparatus ─────────────────────────────────────────────────────
671	
672	  return {
673	    apparatus: {
674	      requires: ['stacks', 'clerk'],
675	      // Recommend `oculus` so the writs page renders the new types via
676	      // its type-vocabulary helper. Without oculus the data is invisible
677	      // to the dashboard; recommending it surfaces a clean startup
678	      // warning when an operator forgets.
679	      recommends: ['oculus'],
680	
681	      supportKit: {
682	        books: {
683	          visions: { indexes: ['stage', 'codex', 'createdAt'] },
684	          charges: { indexes: ['stage', 'codex', 'createdAt'] },
685	          pieces: { indexes: ['stage', 'codex', 'createdAt'] },
686	        },
687	
688	        // Cartograph contributes 16 patron-facing CLI tools — five per
689	        // (vision/charge/piece × create/show/list/patch/transition) plus
690	        // the on-disk authoring tool `vision-apply`. The framework
691	        // `nsg` auto-builder discovers them via The Instrumentarium and
692	        // groups them by hyphen prefix automatically (D2/D3 in the
693	        // commission spec).
694	        tools: [
695	          visionCreate,
696	          visionShow,
697	          visionList,
698	          visionPatch,
699	          visionTransition,
700	          visionApply,
701	          chargeCreate,
702	          chargeShow,
703	          chargeList,
704	          chargePatch,
705	          chargeTransition,
706	          pieceCreate,
707	          pieceShow,
708	          pieceList,
709	          piecePatch,
710	          pieceTransition,
711	        ],
712	      },
713	
714	      provides: api,
715	
716	      start(_ctx: StartupContext): void {
717	        const g = guild();
718	        stacks = g.apparatus<StacksApi>('stacks');
719	        clerk = g.apparatus<ClerkApi>('clerk');
720	
721	        visionsBook = stacks.book<VisionDoc>('cartograph', 'visions');
722	        chargesBook = stacks.book<ChargeDoc>('cartograph', 'charges');
723	        piecesBook = stacks.book<PieceDoc>('cartograph', 'pieces');
724	
725	        // Register the three writ types. Cartograph's `requires: ['stacks',
726	        // 'clerk']` declaration ensures Clerk has already started; the
727	        // registration window stays open until the framework's
728	        // `phase:started` signal seals it.
729	        clerk.registerWritType(VISION_CONFIG);
730	        clerk.registerWritType(CHARGE_CONFIG);
731	        clerk.registerWritType(PIECE_CONFIG);
732	      },
733	    },
734	  };
735	}
736	
737	// Re-export the type-config constants so tests can assert them without
738	// reaching back into the apparatus module.
739	export { VISION_CONFIG, CHARGE_CONFIG, PIECE_CONFIG };
740	
741	// Local type re-exports kept narrow — see ./index.ts for the full surface.
742	export type {
743	  ChargeStage,
744	  PieceStage,
745	  VisionStage,
746	  WritPhase,
747	};
