212	/**
213	 * Atomic-ish sidecar rewrite: write to a temp file in the same
214	 * directory, then rename over the target. Same-directory rename is
215	 * atomic on POSIX filesystems; this avoids the partial-write window
216	 * that would lose the visionId binding on a process crash.
217	 */
218	async function writeSidecarAtomically(
219	  sidecarPath: string,
220	  contents: string,
221	): Promise<void> {
222	  const tmp = `${sidecarPath}.tmp-${process.pid}-${Date.now()}`;
223	  await writeFile(tmp, contents, 'utf8');
224	  await rename(tmp, sidecarPath);
225	}
226	
227	/**
228	 * Round-trip-write the visionId back into the sidecar Document so
229	 * comments and key order survive. Re-emits the document via yaml's
230	 * stringifier, then writes atomically.
231	 */
232	async function persistVisionId(
233	  sidecar: ParsedSidecar,
234	  sidecarPath: string,
235	  visionId: string,
236	): Promise<void> {
237	  sidecar.doc.set('visionId', visionId);
238	  const updated = sidecar.doc.toString();
239	  await writeSidecarAtomically(sidecarPath, updated);
240	}
